"use strict";require("../common/vendor.js");const r=require("../utils/request.js");exports.adminLogin=function(e,s){return r.post("/admin/login",{username:e,password:s})},exports.getUserInfo=function(){return r.get("/user/info")},exports.login=function(e,s){return r.post("/user/login",{phone:e,code:s})},exports.loginByPassword=function(e,s){return r.post("/user/login/password",{username:e,password:s})},exports.register=function(e){return r.post("/user/register",e)};
